"arn:aws:execute-api:us-east-1:123412341234:aaaaa11111/*"
]
}
]
}
{
"Statement": [
{
"Principal": "*",
"Action": [
"execute-api:Invoke"
],
"Effect": "Allow",
"Resource": [
